// Note: In a full program, 'using namespace std;' or 'std::' prefixes would be needed.

int main()
{
  const int NUM_EMPLOYEES = 6;
  int hours[NUM_EMPLOYEES];
  int count;

  // Input the hours worked.
  // Initial state: hours array is uninitialized.
  // count starts at 0
  for (count = 0; count < NUM_EMPLOYEES; count++)
  {
    // Iteration 1: count = 0
    //   Output: "Enter the hours worked by employee 1: "
    //   Input: 20. hours[0] = 20. Array: {20, ?, ?, ?, ?, ?}

    // Iteration 2: count = 1
    //   Output: "Enter the hours worked by employee 2: "
    //   Input: 12. hours[1] = 12. Array: {20, 12, ?, ?, ?, ?}

    // Iteration 3: count = 2
    //   Output: "Enter the hours worked by employee 3: "
    //   Input: 40. hours[2] = 40. Array: {20, 12, 40, ?, ?, ?}

    // Iteration 4: count = 3
    //   Output: "Enter the hours worked by employee 4: "
    //   Input: 30. hours[3] = 30. Array: {20, 12, 40, 30, ?, ?}

    // Iteration 5: count = 4
    //   Output: "Enter the hours worked by employee 5: "
    //   Input: 30. hours[4] = 30. Array: {20, 12, 40, 30, 30, ?}

    // Iteration 6: count = 5
    //   Output: "Enter the hours worked by employee 6: "
    //   Input: 15. hours[5] = 15. Array: {20, 12, 40, 30, 30, 15}
  }
  // After input loop, count becomes 6, loop condition (6 < 6) is false.
  // State of hours array: {20, 12, 40, 30, 30, 15}

  // Display the contents of the array.
  // count resets to 0 for this loop
  std::cout << "The hours you entered are:"; // Output: "The hours you entered are:"
  for (count = 0; count < NUM_EMPLOYEES; count++)
  {
    // Iteration 1: count = 0. Output: " " + hours[0] (20) -> " 20"
    // Iteration 2: count = 1. Output: " " + hours[1] (12) -> " 12"
    // Iteration 3: count = 2. Output: " " + hours[2] (40) -> " 40"
    // Iteration 4: count = 3. Output: " " + hours[3] (30) -> " 30"
    // Iteration 5: count = 4. Output: " " + hours[4] (30) -> " 30"
    // Iteration 6: count = 5. Output: " " + hours[5] (15) -> " 15"
  }
  // After display loop, count becomes 6.
  std::cout << std::endl; // Output: (newline)
  return 0;
}
```

