#include <limits> // Required for std::numeric_limits

int main()
{
  const int NUM_EMPLOYEES = 6;
  int hours[NUM_EMPLOYEES];
  int count;
  // Initialize maxHours to the smallest possible int value to ensure any input is greater
  int maxHours = std::numeric_limits<int>::min(); 

  // Input the hours worked.
  for (count = 0; count < NUM_EMPLOYEES; count++)
  {
    std::cout << "Enter the hours worked by employee "
              << (count + 1) << ": ";
    std::cin >> hours[count];
    // Update maxHours if current hours[count] is greater
    if (hours[count] > maxHours)
    {
      maxHours = hours[count];
    }
  }

  // Display the contents of the array.
  std::cout << "The hours you entered are:";
  for (count = 0; count < NUM_EMPLOYEES; count++)
  {
    std::cout << " " << hours[count];
  }
  std::cout << std::endl;

  // Display maximum hours
  std::cout << "Maximum hours worked by an employee: " << maxHours << std::endl;

  return 0;
}
```

