#include <array> // Using std::array for fixed-size array

int main() {
    std::array<int, 5> numbers = {10, 20, 30, 40, 50};

    std::cout << "Original array elements: ";
    for (int num : numbers) {
        std::cout << num << " ";
    }
    std::cout << std::endl;

    // Attempt to modify using range-based for loop (will not work as expected)
    for (int num : numbers) {
        num = 0; // This modifies the COPY 'num', not the original element in 'numbers'
    }

    std::cout << "Array elements after attempted modification with range-based for loop: ";
    for (int num : numbers) {
        std::cout << num << " ";
    }
    std::cout << std::endl;

