    for (double val : values) {
        std::cout << val << " ";
    }
    std::cout << std::endl;

    // Modify using range-based for loop with a reference
    for (double& val : values) { // 'val' is now a REFERENCE to the original element
        val *= 2; // Modifies the original element in the vector
    }

    std::cout << "Vector elements after doubling with reference: ";
    for (double val : values) {
        std::cout << val << " ";
    }
