#include <iostream>
#include <algorithm> // Required for std::copy

int main() {
    const int SIZE = 4;
    int sourceArray[SIZE] = {10, 20, 30, 40};
    int destinationArray[SIZE]; // Destination array of the same size

    // Method 1: Using a loop (most common for C-style arrays)
    std::cout << "Copying using a loop:\n";
    for (int i = 0; i < SIZE; ++i) {
        destinationArray[i] = sourceArray[i];
    }

    std::cout << "Source Array: ";
    for (int i = 0; i < SIZE; ++i) {
        std::cout << sourceArray[i] << " ";
