    std::cout << "Destination Array: ";
    for (int i = 0; i < SIZE; ++i) {
        std::cout << destinationArray[i] << " ";
    }
    std::cout << std::endl;

    // Method 2: Using std::copy from <algorithm> (more concise)
    int anotherDestinationArray[SIZE];
    std::copy(sourceArray, sourceArray + SIZE, anotherDestinationArray);

    std::cout << "\nCopying using std::copy:\n";
    std::cout << "Source Array: ";
    for (int i = 0; i < SIZE; ++i) {
        std::cout << sourceArray[i] << " ";
