#include <iostream>
#include <iomanip> // For std::fixed and std::setprecision

int main() {
    const int NUM_GRADES = 4;
    double grades[NUM_GRADES] = {85.5, 90.0, 78.2, 92.1};
    double total = 0.0; // Initialize accumulator for double values
    double average;

    // Step 1: Sum the values
    for (int count = 0; count < NUM_GRADES; count++) {
        total += grades[count];
    }

    // Step 2: Calculate the average
    average = total / NUM_GRADES;

    std::cout << std::fixed << std::setprecision(2); // Format output to 2 decimal places
    std::cout << "The total of the grades is: " << total << std::endl;
    std::cout << "The average grade is: " << average << std::endl;
