// Function to find the index of the first difference
int findFirstDifferenceIndex(const int arr1[], const int arr2[], int size) {
    for (int i = 0; i < size; ++i) {
        if (arr1[i] != arr2[i]) {
            return i; // Return the index where the first difference is found
        }
    }
    return -1; // If the loop completes, arrays are identical
}

int main() {
