    int arrayA[SIZE] = {1, 2, 3, 4, 5};
    int arrayB[SIZE] = {1, 2, 3, 4, 5};
    int arrayC[SIZE] = {1, 2, 9, 4, 5}; // Differs at index 2
    int arrayD[SIZE] = {1, 2, 3, 4, 9}; // Differs at index 4

    int diffIndex1 = findFirstDifferenceIndex(arrayA, arrayB, SIZE);
    if (diffIndex1 != -1) {
        std::cout << "arrayA and arrayB differ at index: " << diffIndex1 << std::endl;
    } else {
        std::cout << "arrayA and arrayB are identical.\n";
    }

    int diffIndex2 = findFirstDifferenceIndex(arrayA, arrayC, SIZE);
    if (diffIndex2 != -1) {
        std::cout << "arrayA and arrayC differ at index: " << diffIndex2 << std::endl; // Expected: 2
    } else {
        std::cout << "arrayA and arrayC are identical.\n";
