    int diffIndex3 = findFirstDifferenceIndex(arrayA, arrayD, SIZE);
    if (diffIndex3 != -1) {
        std::cout << "arrayA and arrayD differ at index: " << diffIndex3 << std::endl; // Expected: 4
    } else {
        std::cout << "arrayA and arrayD are identical.\n";
    }

