#include <iostream> // For potential output or error messages

double getAverage(const double numbers[], int size)
{
  if (size == 0) {
    // Handle empty array case: return 0.0 or throw an error
    std::cerr << "Error: Cannot calculate average of an empty array." << std::endl;
    return 0.0; // Or NaN, or throw an exception
  }

  double total = 0; // Accumulator
  for (int count = 0; count < size; count++)
  {
    total += numbers[count]; // Add each element to total
  }

  return total / size; // Return the average
