void showArrayReverse(const int numbers[][COLS_EX], int rows) {
    for (int x = rows - 1; x >= 0; x--) { // Iterate rows in reverse order
        for (int y = COLS_EX - 1; y >= 0; y--) { // Iterate columns in reverse order
            std::cout << std::setw(4) << numbers[x][y] << " "; // Print element with formatting
        }
        std::cout << std::endl; // Newline after each reversed row
    }
}

int main() {
