// Step 1: Define the function signature
bool areArraysIdentical(const int arr1[], const int arr2[], int size) {
    // Step 2: Iterate through the arrays from the first element to the last.
    for (int i = 0; i < size; ++i) {
        // Step 3: Compare elements at each corresponding index.
        if (arr1[i] != arr2[i]) {
            // Step 4: If any elements differ, the arrays are not identical.
            // Immediately return false as there's no need to check further.
            return false;
        }
