// Step 1: Define the function signature. It returns an int (the max value)
// and takes a const int array and its size.
int findMax(const int arr[], int size) {
    // Step 2: Handle edge case for an empty array.
    // Returning the minimum possible int value or throwing an exception
    // are common ways to indicate an invalid input for this scenario.
    if (size <= 0) {
        std::cerr << "Error: Cannot find max in an empty array.\n";
        return std::numeric_limits<int>::min(); // Return smallest possible int
    }

    // Step 3: Initialize max_val with the first element of the array.
    // We assume the array has at least one element due to the check above.
    int max_val = arr[0];

    // Step 4: Iterate through the rest of the array, starting from the second element.
    for (int i = 1; i < size; ++i) {
        // Step 5: If the current element is greater than the current max_val,
        // update max_val to this new larger element.
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    // Step 6: After checking all elements, max_val will hold the largest value.
    return max_val;
}

int main() {
    const int SIZE1 = 5;
    int data1[SIZE1] = {10, 5, 20, 15, 30};

    const int SIZE2 = 3;
    int data2[SIZE2] = {-1, -5, -2};

    const int SIZE3 = 1;
    int data3[SIZE3] = {100};

    // Step 7: Test the function with different arrays and print results.
    std::cout << "Max in data1: " << findMax(data1, SIZE1) << std::endl; // Expected: 30
    std::cout << "Max in data2: " << findMax(data2, SIZE2) << std::endl; // Expected: -1
    std::cout << "Max in data3: " << findMax(data3, SIZE3) << std::endl; // Expected: 100
    std::cout << "Max in empty array: " << findMax(nullptr, 0) << std::endl; // Expected error message and min_int

    return 0;
}
