// Step 1: Define the function signature. It returns an int (the count)
// and takes a const int array, its size, and the target value to search for.
int countOccurrences(const int arr[], int size, int target) {
    // Step 2: Initialize a counter variable to 0. This will store the number of times
    // the target value is found.
    int count = 0;

    // Step 3: Iterate through the array from the first element to the last.
    for (int i = 0; i < size; ++i) {
        // Step 4: Check if the current element of the array matches the target value.
        if (arr[i] == target) {
            // Step 5: If a match is found, increment the counter.
            count++;
        }
    }
    // Step 6: After checking all elements, return the final count.
    return count;
}

