// Step 1: Define the function signature. It's a void function as it modifies the array in place.
// The array parameter is NOT const because its contents will be changed.
void reverseArray(int arr[], int size) {
    // Step 2: Initialize two pointers: 'start' at the beginning of the array
    // and 'end' at the end of the array.
    int start = 0;
    int end = size - 1;

    // Step 3: Loop as long as the 'start' pointer is less than the 'end' pointer.
    // When start >= end, the array is fully reversed or has an odd number of elements
    // and the middle element is in place.
    while (start < end) {
        // Step 4: Swap the elements at the 'start' and 'end' positions.
        // Option A: Manual swap using a temporary variable.
        int temp = arr[start];
        arr[start] = arr[end];
        arr[end] = temp;

        // Option B: Using std::swap from the <algorithm> header.
        // std::swap(arr[start], arr[end]);

        // Step 5: Move the 'start' pointer one position to the right
        // and the 'end' pointer one position to the left.
        start++;
        end--;
    }
}

int main() {
    const int SIZE_EVEN = 6;
    int data_even[SIZE_EVEN] = {1, 2, 3, 4, 5, 6};

    const int SIZE_ODD = 5;
    int data_odd[SIZE_ODD] = {10, 20, 30, 40, 50};

    const int SIZE_ONE = 1;
    int data_one[SIZE_ONE] = {99};

    const int SIZE_EMPTY = 0;
    int data_empty[] = {};

    // Step 6: Demonstrate reversing an array with an even number of elements.
    std::cout << "Original even array: ";
    printArray(data_even, SIZE_EVEN);
    reverseArray(data_even, SIZE_EVEN);
    std::cout << "Reversed even array: ";
    printArray(data_even, SIZE_EVEN); // Expected: 6 5 4 3 2 1

    // Step 7: Demonstrate reversing an array with an odd number of elements.
    std::cout << "\nOriginal odd array: ";
    printArray(data_odd, SIZE_ODD);
    reverseArray(data_odd, SIZE_ODD);
    std::cout << "Reversed odd array: ";
    printArray(data_odd, SIZE_ODD); // Expected: 50 40 30 20 10

    // Step 8: Demonstrate reversing an array with a single element.
    std::cout << "\nOriginal single element array: ";
    printArray(data_one, SIZE_ONE);
    reverseArray(data_one, SIZE_ONE);
    std::cout << "Reversed single element array: ";
    printArray(data_one, SIZE_ONE); // Expected: 99

    // Step 9: Demonstrate reversing an empty array (should do nothing).
    std::cout << "\nOriginal empty array: ";
    printArray(data_empty, SIZE_EMPTY);
    reverseArray(data_empty, SIZE_EMPTY);
    std::cout << "Reversed empty array: ";
    printArray(data_empty, SIZE_EMPTY); // Expected: (nothing)

    return 0;
}
