    // Calculate the average, handling empty vector case
    if (grades.size() > 0) {
        double average = totalSum / grades.size();
        std::cout << std::fixed << std::setprecision(2); // Format output to 2 decimal places
        std::cout << "Total elements: " << grades.size() << std::endl;
        std::cout << "Sum of elements: " << totalSum << std::endl;
        std::cout << "Average of elements: " << average << std::endl;
    } else {
        std::cout << "The vector is empty, cannot calculate average." << std::endl;
    }

    return 0;
}
