// Function to find the maximum value in a vector of integers
int findMaxVector(const std::vector<int>& vec) {
    // 1. Handle empty vector case:
    //    If the vector is empty, it's impossible to find a maximum. 
    //    You might throw an exception, return a sentinel value (e.g., INT_MIN from <limits>), 
    //    or handle it based on program requirements.
    if (vec.empty()) {
        // Example: throw std::runtime_error("Cannot find max in an empty vector");
        // Or return a very small number if appropriate for the context
        return -1; // Or some other indicator of error/no max
    }

    // 2. Initialize maximum:
    //    Set the initial maximum to the first element of the vector.
    int maxVal = vec[0];

    // 3. Iterate through the rest of the vector:
    //    Compare each subsequent element with the current maximum.
    for (size_t i = 1; i < vec.size(); ++i) {
        if (vec[i] > maxVal) {
            maxVal = vec[i];
        }
    }

    // 4. Return the maximum value found.
    return maxVal;
}
